    }

    // Deduct stock
    product.stock -= item.quantity;

    const itemTotal = product.price * item.quantity;
    orderItems.push({
      productId: product.id,
      quantity: item.quantity,
      price: product.price,
    });
    total += itemTotal;
  }

  const order = {
    id: getNextOrderId(),
    userId: input.userId,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending" as const,
    createdAt: new Date().toISOString(),
  };

  orders.push(order);

  res.status(201).json(order);
});

// PATCH /orders/:id/status - update order status
router.patch("/orders/:id/status", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const order = orders.find((o) => o.id === id);

  if (!order) {
    res.status(404).json({ error: "Order not found" });
    return;
  }

  const { status } = req.body as { status: string };
  const validStatuses = ["pending", "confirmed", "shipped", "delivered"];

  if (!validStatuses.includes(status)) {
    res.status(400).json({ error: `Invalid status. Must be one of: ${validStatuses.join(", ")}` });
    return;
  }

  // Validate status transitions
  const transitions: Record<string, string[]> = {
    pending: ["confirmed"],
    confirmed: ["shipped"],
    shipped: ["delivered"],
    delivered: [],
  };

  if (!transitions[order.status]?.includes(status)) {
    res.status(400).json({
      error: `Cannot transition from ${order.status} to ${status}`,
    });
    return;
  }

  order.status = status as typeof order.status;

  res.json(order);
});

export { router as orderRouter };
```

---

### 4. **Business Logic in Route Handlers**

#### **Products Routes:**
1. **GET /products** - List and filter products
   - Filter by category, minPrice, maxPrice
   - Calculate total inventory value (price × stock for all items)
   - Calculate average price across filtered products
   - Returns products array + summary stats

2. **GET /products/:id** - Get single product details
   - Calculate `isLowStock` flag (stock < 10)
   - Calculate `inventoryValue` (price × stock)
   - Return enriched product with calculated fields

3. **PATCH /products/:id/stock** - Update product stock
   - Validate adjustment is a number
   - Prevent negative stock
   - Update product.stock directly
   - Return enriched product with calculated fields

#### **Orders Routes:**
1. **GET /orders** - List and filter orders
   - Filter by userId, status
   - Calculate totalRevenue across filtered orders
   - Returns orders array + summary stats

2. **GET /orders/:id** - Get single order with enriched data
   - Enrich order items by joining with products table
   - Add `productName` field to each order item
   - Handle missing products gracefully ("Unknown")

3. **POST /orders** - Create new order
   - Validate userId and items array presence
   - Validate non-empty items
   - For each item: validate product exists, validate quantity > 0, validate stock availability
   - **Deduct stock immediately** from products (side effect)
   - Calculate order total
   - Store in orders array with "pending" status
   - Return 201 with created order

4. **PATCH /orders/:id/status** - Update order status
   - Validate status is in allowed list
   - Validate state transition rules (pending→confirmed→shipped→delivered)
   - Only allows forward transitions
   - Prevents invalid transitions (e.g., confirmed→pending)

---

### 5. **Separation of Concerns - CURRENT STATE**

**There is NO service layer**. The application follows a single-layer architecture:

- **Route Handlers** (`/routes/*.ts`) contain ALL business logic:
  - Filtering/querying logic
  - Validation logic
  - Calculations (inventory value, averages, totals)
  - State mutations (stock deduction, order creation)
  - State transition logic

- **Data Layer** (`data.ts`):
  - Simple in-memory arrays (no ORM, no database client)
  - Basic utility function `getNextOrderId()`

**Problems with current architecture:**
1. Business logic is tightly coupled to HTTP layer
2. Difficult to test business rules without HTTP calls
3. No reusability - same validation/calculation logic duplicated
4. Hard to maintain - changes to business rules require modifying route files
5. No transaction management or atomicity guarantees

---

### 6. **ORM/Database Layer**

**Current Implementation:**
- **No ORM** - Direct in-memory JavaScript arrays
- **No database** - Just `data.ts` with hardcoded arrays
- **No persistence** - Data resets on restart
- **Manual ID management** - `getNextOrderId()` function

**Data Structure:**
- `products: Product[]` - 5 sample products
- `orders: Order[]` - 2 sample orders
- Global counter: `nextOrderId` starts at 3

---

### 7. **Main App Entry Point**

**File: `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775508428037-hy49dj/src/app.ts`**

```typescript
import express from "express";
import { productRouter } from "./routes/products.js";
import { orderRouter } from "./routes/orders.js";

const app = express();
app.use(express.json());
app.use(productRouter);
app.use(orderRouter);

export { app };
```

- Very simple Express setup
- JSON body parser middleware
- Routes mounted directly without path prefixes

---

### Summary Table

| Aspect | Details |
|--------|---------|
| **Framework** | Express.js 4.21.0 |
| **Language** | TypeScript 5.7 (strict mode) |
| **Routes** | 2 files (products, orders) |
| **Total Endpoints** | 6 HTTP endpoints |
| **Data Storage** | In-memory arrays (no database/ORM) |
| **Service Layer** | None - logic in route handlers |
| **Testing** | Vitest + Supertest (2 test files) |
| **Architecture** | Single-layer (no separation of concerns) |

This codebase is a prime candidate for **service layer extraction** - the business logic should be moved out of route handlers into dedicated service classes/functions.

