### 4. Refactored Route Handler Structure (Pseudocode)

#### `src/routes/products.ts` (after refactoring)

```typescript
import { Router } from "express";
import { listProducts, getProductById, adjustProductStock } from "../services/productService.js";
import { NotFoundError, ValidationError } from "../errors.js";

const router = Router();

router.get("/products", (req, res) => {
  const category = typeof req.query.category === "string" ? req.query.category : undefined;
  const minPrice = typeof req.query.minPrice === "string" ? parseFloat(req.query.minPrice) : undefined;
  const maxPrice = typeof req.query.maxPrice === "string" ? parseFloat(req.query.maxPrice) : undefined;

  const result = listProducts({
    category,
    minPrice: minPrice !== undefined && !isNaN(minPrice) ? minPrice : undefined,
    maxPrice: maxPrice !== undefined && !isNaN(maxPrice) ? maxPrice : undefined,
  });

  res.json(result);
});

router.get("/products/:id", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const product = getProductById(id);
    res.json(product);
  } catch (err) {
    if (err instanceof NotFoundError) {
      res.status(404).json({ error: err.message });
      return;
    }
    throw err;
  }
});

router.patch("/products/:id/stock", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const { adjustment } = req.body as { adjustment: number };
    const product = adjustProductStock(id, adjustment);
    res.json(product);
  } catch (err) {
    if (err instanceof NotFoundError) {
      res.status(404).json({ error: err.message });
      return;
    }
    if (err instanceof ValidationError) {
      res.status(400).json({ error: err.message });
      return;
    }
    throw err;
  }
});

export { router as productRouter };
```

