import { listOrders, getOrderById, createOrder, updateOrderStatus } from "../services/orderService.js";
import { NotFoundError, ValidationError } from "../errors.js";
import type { CreateOrderInput } from "../types.js";

const router = Router();

router.get("/orders", (req, res) => {
  const userId = typeof req.query.userId === "string" ? parseInt(req.query.userId, 10) : undefined;
  const status = typeof req.query.status === "string" ? req.query.status : undefined;

  const result = listOrders({
    userId: userId !== undefined && !isNaN(userId) ? userId : undefined,
    status,
  });

  res.json(result);
});

router.get("/orders/:id", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const order = getOrderById(id);
    res.json(order);
  } catch (err) {
    if (err instanceof NotFoundError) {
      res.status(404).json({ error: err.message });
      return;
    }
    throw err;
  }
});

router.post("/orders", (req, res) => {
  try {
    const input = req.body as CreateOrderInput;
    const order = createOrder(input);
    res.status(201).json(order);
  } catch (err) {
    if (err instanceof ValidationError) {
      res.status(400).json({ error: err.message });
      return;
    }
    throw err;
  }
});

router.patch("/orders/:id/status", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const { status } = req.body as { status: string };
    const order = updateOrderStatus(id, status);
    res.json(order);
  } catch (err) {
    if (err instanceof NotFoundError) {
      res.status(404).json({ error: err.message });
      return;
    }
    if (err instanceof ValidationError) {
      res.status(400).json({ error: err.message });
      return;
    }
    throw err;
  }
});

export { router as orderRouter };
```

Key observations about the route handlers:
- They only parse `req.params`, `req.query`, and `req.body`.
- They delegate entirely to service functions.
- They catch service errors and map `NotFoundError` to 404, `ValidationError` to 400.
- They set the response status code and call `res.json()`.
- The `GET /products` handler does not need try/catch because `listProducts` never throws.
- The `GET /orders` handler similarly needs no try/catch.
- The query param parsing (checking `typeof === "string"`, `parseFloat`, `parseInt`, `isNaN`) stays in routes because that is HTTP-layer concern (parsing raw query strings into typed values).

---

### 5. File Organization

New files to create:

```
src/
├── errors.ts              (NEW)
├── services/
│   ├── productService.ts  (NEW)
│   └── orderService.ts    (NEW)
├── types.ts               (MODIFIED - add new interfaces)
├── data.ts                (UNCHANGED)
├── app.ts                 (UNCHANGED)
└── routes/
    ├── products.ts        (MODIFIED - thin HTTP layer)
    └── orders.ts          (MODIFIED - thin HTTP layer)
tests/
├── products.test.ts       (UNCHANGED)
└── orders.test.ts         (UNCHANGED)
```

The `src/services/` directory is new. The convention of co-locating services in a `services/` sibling to `routes/` is standard and mirrors the existing structure.

---

### 6. Step-by-Step Implementation Order

The order is designed so the tests can pass at every intermediate step (each step leaves the app in a compilable, test-passing state).

**Step 1: Create `src/errors.ts`**

Create the file with `ServiceError`, `NotFoundError`, and `ValidationError`. This is a leaf module with no imports from the project, so it cannot break anything. No existing code references it yet.

**Step 2: Add new types to `src/types.ts`**

Add `ProductFilters`, `EnrichedProduct`, `ProductSummary`, `ProductListResult`, `OrderFilters`, `OrderSummary`, `OrderListResult`, `EnrichedOrderItem`, `EnrichedOrder`, and `OrderStatus`. These are purely additive -- no existing code is changed, and all existing type exports remain intact.

**Step 3: Create `src/services/productService.ts`**

Implement `listProducts`, `getProductById`, and `adjustProductStock`. The logic is copied from the route handlers, with `res.status(...).json(...)` replaced by `throw new NotFoundError/ValidationError(...)` and return statements. This file imports from `../data.js`, `../types.js`, and `../errors.js`. It is a leaf module that nothing references yet.

**Step 4: Refactor `src/routes/products.ts` to use the product service**

Replace the inline business logic with calls to the three service functions. Add try/catch blocks that map errors to HTTP responses. Remove the import of `products` from `../data.js`; replace with imports from `../services/productService.js` and `../errors.js`.

**Run tests after Step 4.** All product tests should pass. Order tests are untouched.

**Step 5: Create `src/services/orderService.ts`**

Implement `listOrders`, `getOrderById`, `createOrder`, and `updateOrderStatus`. Same approach as Step 3.

**Step 6: Refactor `src/routes/orders.ts` to use the order service**

Replace inline business logic with calls to the four service functions. Add try/catch blocks. Adjust imports.

**Run tests after Step 6.** All tests should pass.

---

### Potential Pitfalls and Mitigations

1. **Error message exact-match sensitivity.** The tests do not assert on specific error messages (they only check status codes), so the error strings can be lifted verbatim without risk. I verified this by reading both test files -- no `.body.error` assertions exist.

2. **Query param parsing for `NaN`.** The current `GET /products` handler silently ignores `minPrice`/`maxPrice` if `parseFloat` returns `NaN`. The route handler must continue to do this check before passing to the service. The service receives already-validated `number | undefined`.

3. **The `typeof adjustment !== "number"` check in `adjustProductStock`.** When Express parses a JSON body, `adjustment` will be a number if the client sent JSON. But the current route checks `typeof adjustment !== "number"` as a guard. This validation should move into the service since it is a business rule (the adjustment must be numeric). The route simply does `req.body.adjustment` and passes it through. The service validates the type.

4. **Mutation side effects in `createOrder`.** The current handler deducts stock from products as it validates items. If validation fails midway through the items array, some stock has already been deducted. The current code has this bug (or feature). The service should replicate the exact same behavior to preserve test compatibility. A future improvement would be to validate all items first, then deduct, but that is out of scope for this refactoring.

5. **ES module `.js` extensions.** All new imports must use `.js` extensions (e.g., `../services/productService.js`), matching the existing convention and the `Node16` module resolution.

6. **The `listProducts` handler has no try/catch.** Since `listProducts` cannot throw, no error mapping is needed. Same for `listOrders`. This keeps the handlers maximally thin.

