import {
  listOrders,
  getOrderById,
  createOrder,
  updateOrderStatus,
} from "../services/orderService.js";
import { NotFoundError, ValidationError } from "../errors.js";
import type { CreateOrderInput } from "../types.js";

const router = Router();

// GET /orders - list orders, optionally filter by userId or status
router.get("/orders", (req, res) => {
  const userIdRaw =
    typeof req.query.userId === "string"
      ? parseInt(req.query.userId, 10)
      : undefined;
  const status =
    typeof req.query.status === "string" ? req.query.status : undefined;

  const result = listOrders({
    userId:
      userIdRaw !== undefined && !isNaN(userIdRaw) ? userIdRaw : undefined,
    status,
  });

  res.json(result);
});

// GET /orders/:id
router.get("/orders/:id", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const order = getOrderById(id);
    res.json(order);
  } catch (err) {
    if (err instanceof NotFoundError) {
      res.status(404).json({ error: err.message });
      return;
    }
    throw err;
  }
});

// POST /orders - create a new order
router.post("/orders", (req, res) => {
  try {
    const input = req.body as CreateOrderInput;
    const order = createOrder(input);
    res.status(201).json(order);
  } catch (err) {
    if (err instanceof ValidationError) {
      res.status(400).json({ error: err.message });
      return;
    }
    throw err;
  }
});

// PATCH /orders/:id/status - update order status
router.patch("/orders/:id/status", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const { status } = req.body as { status: string };
    const order = updateOrderStatus(id, status);
    res.json(order);
  } catch (err) {
    if (err instanceof NotFoundError) {
      res.status(404).json({ error: err.message });
      return;
    }
    if (err instanceof ValidationError) {
      res.status(400).json({ error: err.message });
      return;
    }
    throw err;
  }
});

export { router as orderRouter };

